#!/usr/bin/env node
/**
 * Generates per-route lastModified timestamps from git history for sitemap.xml.
 *
 * Problem: pre-J-1 sitemap used `new Date()` for every static route, so each
 * sitemap regeneration declared all 31 main/content/tool/legal pages as modified
 * "right now". Google has no per-URL freshness signal and treats sitemap as noise.
 *
 * Fix: for each route, take the newest git commit time across:
 *   - the route's page.tsx
 *   - the route's layout.tsx (if present)
 *
 * Output: src/lib/generated-route-mtimes.ts — committed to git as a fallback;
 * regenerated by `npm run prebuild` on every build so Vercel deploys carry an
 * up-to-date snapshot.
 *
 * Routes that translate via messages/*.json could in principle also bump mtime
 * on translation edits — out of scope for J-1; revisit if SEO measurement shows
 * stale lastModified on long-untouched pages whose copy actually moved.
 */
import { execSync } from 'node:child_process';
import { existsSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const REPO_ROOT = join(__dirname, '..');

// Keep in lockstep with sitemap.ts mainPaths/contentPaths/toolPaths/legalPaths.
// If a route is added there, add its file mapping here too.
const ROUTE_FILES = {
    '': ['src/app/[locale]/page.tsx', 'src/app/[locale]/layout.tsx'],
    '/o-nas': ['src/app/[locale]/o-nas/page.tsx', 'src/app/[locale]/o-nas/layout.tsx'],
    '/oferta': ['src/app/[locale]/oferta/page.tsx', 'src/app/[locale]/oferta/layout.tsx'],
    '/oferta/implantologia': ['src/app/[locale]/oferta/implantologia/page.tsx', 'src/app/[locale]/oferta/implantologia/layout.tsx'],
    '/oferta/leczenie-kanalowe': ['src/app/[locale]/oferta/leczenie-kanalowe/page.tsx', 'src/app/[locale]/oferta/leczenie-kanalowe/layout.tsx'],
    '/oferta/stomatologia-estetyczna': ['src/app/[locale]/oferta/stomatologia-estetyczna/page.tsx', 'src/app/[locale]/oferta/stomatologia-estetyczna/layout.tsx'],
    '/oferta/ortodoncja': ['src/app/[locale]/oferta/ortodoncja/page.tsx', 'src/app/[locale]/oferta/ortodoncja/layout.tsx'],
    '/oferta/chirurgia': ['src/app/[locale]/oferta/chirurgia/page.tsx', 'src/app/[locale]/oferta/chirurgia/layout.tsx'],
    '/oferta/protetyka': ['src/app/[locale]/oferta/protetyka/page.tsx', 'src/app/[locale]/oferta/protetyka/layout.tsx'],
    '/cennik': ['src/app/[locale]/cennik/page.tsx', 'src/app/[locale]/cennik/layout.tsx'],
    '/kontakt': ['src/app/[locale]/kontakt/page.tsx', 'src/app/[locale]/kontakt/layout.tsx'],
    '/rezerwacja': ['src/app/[locale]/rezerwacja/page.tsx', 'src/app/[locale]/rezerwacja/layout.tsx'],
    '/dla-pacjentow-przyjezdnych': ['src/app/[locale]/dla-pacjentow-przyjezdnych/page.tsx', 'src/app/[locale]/dla-pacjentow-przyjezdnych/layout.tsx'],
    '/aktualnosci': ['src/app/[locale]/aktualnosci/page.tsx', 'src/app/[locale]/aktualnosci/layout.tsx'],
    '/baza-wiedzy': ['src/app/[locale]/baza-wiedzy/page.tsx', 'src/app/[locale]/baza-wiedzy/layout.tsx'],
    '/metamorfozy': ['src/app/[locale]/metamorfozy/page.tsx', 'src/app/[locale]/metamorfozy/layout.tsx'],
    '/sklep': ['src/app/[locale]/sklep/page.tsx', 'src/app/[locale]/sklep/layout.tsx'],
    '/faq': ['src/app/[locale]/faq/page.tsx', 'src/app/[locale]/faq/layout.tsx'],
    '/nowosielski': ['src/app/[locale]/nowosielski/page.tsx', 'src/app/[locale]/nowosielski/layout.tsx'],
    '/mapa-bolu': ['src/app/[locale]/mapa-bolu/page.tsx', 'src/app/[locale]/mapa-bolu/layout.tsx'],
    '/kalkulator-leczenia': ['src/app/[locale]/kalkulator-leczenia/page.tsx', 'src/app/[locale]/kalkulator-leczenia/layout.tsx'],
    '/porownywarka': ['src/app/[locale]/porownywarka/page.tsx', 'src/app/[locale]/porownywarka/layout.tsx'],
    '/selfie': ['src/app/[locale]/selfie/page.tsx', 'src/app/[locale]/selfie/layout.tsx'],
    '/symulator': ['src/app/[locale]/symulator/page.tsx', 'src/app/[locale]/symulator/layout.tsx'],
    '/aplikacja': ['src/app/[locale]/aplikacja/page.tsx', 'src/app/[locale]/aplikacja/layout.tsx'],
    '/zadatek': ['src/app/[locale]/zadatek/page.tsx'],
    '/regulamin': ['src/app/[locale]/regulamin/page.tsx', 'src/app/[locale]/regulamin/layout.tsx'],
    '/polityka-cookies': ['src/app/[locale]/polityka-cookies/page.tsx', 'src/app/[locale]/polityka-cookies/layout.tsx'],
    '/polityka-prywatnosci': ['src/app/[locale]/polityka-prywatnosci/page.tsx', 'src/app/[locale]/polityka-prywatnosci/layout.tsx'],
    '/rodo': ['src/app/[locale]/rodo/page.tsx', 'src/app/[locale]/rodo/layout.tsx'],
    '/privacy-policy': ['src/app/[locale]/privacy-policy/page.tsx', 'src/app/[locale]/privacy-policy/layout.tsx'],
};

function gitMtime(relativeFile) {
    const absolute = join(REPO_ROOT, relativeFile);
    if (!existsSync(absolute)) return null;
    try {
        // %aI = author date, strict ISO 8601 with timezone offset
        const out = execSync(`git log -1 --format=%aI -- "${relativeFile}"`, {
            cwd: REPO_ROOT,
            encoding: 'utf8',
            stdio: ['ignore', 'pipe', 'ignore'],
        }).trim();
        return out || null;
    } catch {
        return null;
    }
}

const mtimes = {};
let missing = 0;

for (const [routePath, files] of Object.entries(ROUTE_FILES)) {
    const dates = files.map(gitMtime).filter(Boolean);
    if (dates.length === 0) {
        missing++;
        continue;
    }
    // Newest commit across the route's files = the route's last modification.
    dates.sort();
    mtimes[routePath] = dates[dates.length - 1];
}

const buildTime = new Date().toISOString();
const content = `// AUTO-GENERATED by scripts/generate-route-mtimes.mjs — DO NOT EDIT.
// Regenerated by \`npm run prebuild\` (and \`npm run generate:mtimes\`).
// Provides per-URL lastModified for sitemap.xml so Google sees real freshness
// signal instead of "every page changed right now" on each sitemap regeneration.

export const routeMtimes: Record<string, string> = ${JSON.stringify(mtimes, null, 4)};

/** Fallback for routes not in the map (e.g. newly added pages before next regen). */
export const buildTime: string = ${JSON.stringify(buildTime)};
`;

const outPath = join(REPO_ROOT, 'src/lib/generated-route-mtimes.ts');
writeFileSync(outPath, content, 'utf8');

const count = Object.keys(mtimes).length;
console.log(`✓ Generated ${count} route mtimes${missing ? ` (${missing} missing — files not found in git)` : ''}`);
console.log(`  Output: ${outPath}`);
